class Solution {
    public List<Integer> sequentialDigits(int low, int high) {
        List<Integer> result = new ArrayList<>();
        for (int i = 1; i <= 9; i++) {
            for (int j = i + 1; j <= 9; j++) {
                for (int k = j + 1; k <= 9; k++) {
                    for (int l = k + 1; l <= 9; l++) {
                        for (int m = l + 1; m <= 9; m++) {
                            int num = Integer.parseInt(String.valueOf(i) + String.valueOf(j) + String.valueOf(k) + String.valueOf(l) + String.valueOf(m));
                            if (num >= low && num <= high) {
                                result.add(num);
                            }
                        }
                    }
                }
            }
        }
        return result;
    }
}
